(function($){'use strict';class GHLCRMRouter{constructor(){this.appContainer=$('#ghl-crm-app');this.currentView=null;this.config=window.ghlCrmSpaConfig||{};this.viewCache={};this.prefetchCache={};this.inflightPrefetch={};this.prefetchTtl=60000;this.currentParams={};this.init()}
init(){$(window).on('hashchange',()=>this.handleRouteChange());this.handleRouteChange()}
handleRouteChange(){const hash=window.location.hash.slice(1)||'/';const route=this.parseRoute(hash);const settingsTabs=(this.config.settings&&this.config.settings.tabs)?this.config.settings.tabs:['general','api','rest-api','webhooks','notifications','sync-options','role-tags','conversations','advanced','stats'];if(settingsTabs.includes(hash)){if(this.currentView!=='settings'){this.loadView('settings')}
return}
this.loadView(route.view,route.params);$(window).trigger('ghl-spa-route-changed',[route.view])}
parseRoute(hash){hash=hash.replace(/^\//,'');if(!hash||hash===''){return{view:'dashboard',params:{}}}
let pathPart=hash;let queryString='';const queryIndex=hash.indexOf('?');if(queryIndex!==-1){pathPart=hash.slice(0,queryIndex);queryString=hash.slice(queryIndex+1)}
const pathSegments=pathPart.split('/').filter(Boolean);const view=pathSegments.shift()||'dashboard';const params={};for(let i=0;i<pathSegments.length;i+=2){const key=pathSegments[i];const value=pathSegments[i+1];if(key&&typeof value!=='undefined'){params[key]=decodeURIComponent(value)}}
if(queryString){const searchParams=new URLSearchParams(queryString);searchParams.forEach((value,key)=>{if(typeof params[key]==='undefined'){params[key]=value}})}
return{view,params}}
loadView(view,params={},callback=null){const cacheKey=this.getCacheKey(view,params);const cached=this.viewCache[cacheKey];const validCache=(entry)=>entry&&(Date.now()-entry.fetchedAt)<this.prefetchTtl;const useEntry=(entry)=>{this.viewCache[cacheKey]=entry;this.currentView=view;this.currentParams=params;this.renderView(entry.data,params);if(typeof callback==='function'){callback()}};if(validCache(cached)){useEntry(cached);return}
this.showLoading();$.ajax({url:this.config.ajaxUrl,type:'POST',data:{action:'ghl_crm_spa_view',nonce:this.config.nonce,view:view,params:params},success:(response)=>{if(response.success&&response.data){this.currentView=view;this.currentParams=params;this.renderView(response.data,params);this.viewCache[cacheKey]={data:response.data,fetchedAt:Date.now(),};if(typeof callback==='function'){callback()}}else{this.showError(response.data?.message||this.config.strings.error)}},error:(xhr,status,error)=>{this.showError(this.config.strings.error)}})}
renderView(viewData,params={}){const view=viewData.view;const html=viewData.html;this.appContainer.html(html);this.initializeViewHandlers(view,params)}
initializeViewHandlers(view,params={}){switch(view){case 'dashboard':if(typeof window.initDashboard==='function'){window.initDashboard()}
if(typeof window.initAnalytics==='function'){const analyticsDataElement=document.getElementById('ghl-analytics-data');if(analyticsDataElement){try{const analyticsData=JSON.parse(analyticsDataElement.textContent);window.initAnalytics(analyticsData)}catch(e){console.error('Failed to parse analytics data:',e)}}else{console.warn('Analytics data element not found')}}
break;case 'field-mapping':if(typeof window.initFieldMapping==='function'){window.initFieldMapping()}
if(window.GHL_FieldMapping){if(typeof window.GHL_FieldMapping.initSelect2==='function'){window.GHL_FieldMapping.initSelect2()}
if(typeof window.GHL_FieldMapping.updateMappedRows==='function'){window.GHL_FieldMapping.updateMappedRows()}}
break;case 'custom-objects':if(typeof window.initCustomObjects==='function'){window.initCustomObjects()}
break;case 'integrations':if(typeof window.initIntegrations==='function'){window.initIntegrations()}
break;case 'settings':if(typeof window.initSettings==='function'){window.initSettings()}
if(typeof window.initUserRegisterTags==='function'){window.initUserRegisterTags()}
if(typeof window.initUserRegisterCompany==='function'){window.initUserRegisterCompany()}
if(typeof window.initRestrictionsTagsSelect==='function'){window.initRestrictionsTagsSelect()}
if(typeof window.initRoleTags==='function'){window.initRoleTags()}
if(typeof window.initFamilyAccounts==='function'){window.initFamilyAccounts()}
if(typeof window.cleanupSettingsMenu==='function'){window.cleanupSettingsMenu()}
if(typeof window.initSettingsMenu==='function'){window.initSettingsMenu()}
break;case 'sync-logs':if(typeof window.GHLSyncLogs!=='undefined'&&typeof window.GHLSyncLogs.init==='function'){window.GHLSyncLogs.init(params)}
break;case 'forms':if(typeof window.GHLFormsManager!=='undefined'){if(typeof window.GHLFormsManager.reset==='function'){window.GHLFormsManager.reset()}
if(typeof window.GHLFormsManager.init==='function'){window.GHLFormsManager.init()}}
break}}
showLoading(){this.appContainer.html(`
                    <div class="ghl-spa-loading">
                        <div class="ghl-skeleton-hero"></div>
                        <div class="ghl-skeleton-grid">
                            <div class="ghl-skeleton-card">
                                <div class="ghl-skeleton-bar wide"></div>
                                <div class="ghl-skeleton-bar"></div>
                                <div class="ghl-skeleton-bar short"></div>
                            </div>
                            <div class="ghl-skeleton-card">
                                <div class="ghl-skeleton-bar wide"></div>
                                <div class="ghl-skeleton-bar"></div>
                                <div class="ghl-skeleton-bar short"></div>
                            </div>
                            <div class="ghl-skeleton-card">
                                <div class="ghl-skeleton-bar wide"></div>
                                <div class="ghl-skeleton-bar"></div>
                                <div class="ghl-skeleton-bar short"></div>
                            </div>
                        </div>
                    </div>
                `)}
showError(message){this.appContainer.html(`
                <div class="notice notice-error">
                    <p><strong>Error:</strong> ${message}</p>
                </div>
            `)}
getCacheKey(view,params={}){try{return `${view}::${JSON.stringify(params || {})}`}catch(e){return view}}
showNotice(message,type='success'){if(typeof Swal!=='undefined'){Swal.fire({toast:!0,position:'top-end',icon:type,title:message,showConfirmButton:!1,timer:3000,timerProgressBar:!0,customClass:{popup:'ghl-swal-top-toast',},didOpen:(toast)=>{toast.addEventListener('mouseenter',Swal.stopTimer);toast.addEventListener('mouseleave',Swal.resumeTimer)}})}else{console.log(`[${type}] ${message}`)}}}
$(document).ready(function(){new GHLCRMRouter()})})(jQuery)